import { FC } from 'react';

import { OneColumnLayout, TwoColumnLayout } from '../Layout';
import { TwoColumnStackedLayoutProps } from '../Layout/Layout.types';
import StackedLayout from '../Layout/StackedLayout';

const TwoColumnStackedLayout: FC<TwoColumnStackedLayoutProps> = ({
  topLeft,
  topRight,
  middle,
  bottomLeft,
  bottomRight,
  topAsideVisibleAtWidth,
  bottomAsideVisibleAtWidth,
  ...rest
}) => (
  <StackedLayout {...rest}>
    <TwoColumnLayout
      main={topLeft}
      aside={topRight}
      asideVisibleAtWidth={topAsideVisibleAtWidth}
    />
    <OneColumnLayout main={middle} />
    <TwoColumnLayout
      main={bottomLeft}
      aside={bottomRight}
      asideVisibleAtWidth={bottomAsideVisibleAtWidth}
    />
  </StackedLayout>
);

export default TwoColumnStackedLayout;
